const DARK_MODE_KEY='sadec-dark-mode';export function initDarkMode(){const prefersDark=window.matchMedia('(prefers-color-scheme: dark)');const savedPreference=localStorage.getItem(DARK_MODE_KEY);if(savedPreference==='dark'||(savedPreference===null&&prefersDark.matches)){document.documentElement.setAttribute('data-theme','dark');}prefersDark.addEventListener('change',(e)=>{if(localStorage.getItem(DARK_MODE_KEY)===null){document.documentElement.setAttribute('data-theme',e.matches ? 'dark' : 'light');}});createToggleButton();}export function toggleDarkMode(){const html=document.documentElement;const currentTheme=html.getAttribute('data-theme');const newTheme=currentTheme==='dark' ? 'light' : 'dark';html.setAttribute('data-theme',newTheme);localStorage.setItem(DARK_MODE_KEY,newTheme);window.dispatchEvent(new CustomEvent('theme-change',{detail:{theme: newTheme}}));}function createToggleButton(){if(document.getElementById('dark-mode-toggle'))return;const toggleBtn=document.createElement('button');toggleBtn.id='dark-mode-toggle';toggleBtn.className='dark-mode-toggle';toggleBtn.setAttribute('aria-label','Toggle dark mode');toggleBtn.innerHTML=`<span class="material-symbols-outlined sun-icon">light_mode</span><span class="material-symbols-outlined moon-icon">dark_mode</span>`;toggleBtn.addEventListener('click',toggleDarkMode);const header=document.querySelector('header')||document.querySelector('.admin-header')||document.body;header.appendChild(toggleBtn);addStyles();}function addStyles(){if(document.getElementById('dark-mode-toggle-styles'))return;const style=document.createElement('style');style.id='dark-mode-toggle-styles';style.textContent=` .dark-mode-toggle{position: fixed;top: 80px;right: 20px;width: 48px;height: 48px;border-radius: 50%;background: var(--md-sys-color-surface-container,rgba(0,0,0,0.05));border: 1px solid var(--md-sys-color-outline,rgba(0,0,0,0.1));cursor: pointer;display: flex;align-items: center;justify-content: center;transition: all 0.3s ease;z-index: 1000;}.dark-mode-toggle:hover{background: var(--md-sys-color-primary-container,rgba(0,106,96,0.1));transform: scale(1.1);}.dark-mode-toggle .sun-icon{display: none;}.dark-mode-toggle .moon-icon{display: block;}[data-theme="dark"] .dark-mode-toggle .sun-icon{display: block;}[data-theme="dark"] .dark-mode-toggle .moon-icon{display: none;}.dark-mode-toggle .material-symbols-outlined{font-size: 24px;color: var(--md-sys-color-on-surface-variant,#666);}*{transition: background-color 0.3s ease,color 0.3s ease,border-color 0.3s ease;}`;document.head.appendChild(style);}if(typeof window!=='undefined'){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initDarkMode);}else{initDarkMode();}}